mapper.select:
select info_id, user_name, ipaddr, login_location, browser, os, status, msg, login_time, event_type, risk_level, biz_category, highlight_tag from sys_logininfor


		AND ipaddr like concat('%', #{ipaddr}, '%')


		AND status = #{status}


		AND user_name like concat('%', #{userName}, '%')


		AND event_type = #{eventType}


		AND risk_level = #{riskLevel}


		AND biz_category = #{bizCategory}


		AND highlight_tag like concat('%', #{highlightTag}, '%')


		AND login_time >= #{params.beginTime}


		AND login_time <= #{params.endTime}


order by info_id desc
